div.script:
document.addEventListener('DOMContentLoaded', function() {
    // Bank selector handling
    const bankOptions = document.querySelectorAll('.bank-option');
    const bankInput = document.getElementById('paratika_bank');
    
    bankOptions.forEach(option => {
        option.addEventListener('click', function() {
            // Remove active class from all
            bankOptions.forEach(o => o.classList.remove('active', 'border-primary'));
            // Add to clicked
            this.classList.add('active', 'border-primary');
            // Set hidden input
            if (bankInput) bankInput.value = this.dataset.bank;
        });
    });
    
    // Installment change handler
    const installmentSelect = document.getElementById('paratika_installment');
    if (installmentSelect) {
        installmentSelect.addEventListener('change', function() {
            // Could trigger AJAX to recalculate amounts
            console.log('Installment changed to:', this.value);
        });
    }
});

t.script:
                    odoo.define('payment_paratika.category_payment_widget', function (require) {
                        'use strict';
                        
                        const publicWidget = require('web.public.widget');
                        const ajax = require('web.ajax');
                        
                        publicWidget.registry.ParatikaCategoryPayment = publicWidget.Widget.extend({
                            selector: '.o_wsale_checkout_form',
                            
                            events: {
                                'change select[name="installmentCount"]': '_onInstallmentChange',
                                'click .bank-option': '_onBankSelect',
                            },
                            
                            start: function () {
                                this._super.apply(this, arguments);
                                this._loadCategoryPaymentMethods();
                                return this._super(...arguments);
                            },
                            
                            _loadCategoryPaymentMethods: function () {
                                const self = this;
                                const saleOrderId = this.$el.find('input[name="sale_order_id"]').val();
                                
                                if (!saleOrderId) return;
                                
                                this._rpc({
                                    route: '/payment/paratika/category_methods',
                                    params: { sale_order_id: parseInt(saleOrderId) }
                                }).then(function (result) {
                                    if (result.payment_methods) {
                                        self._updatePaymentMethods(result.payment_methods);
                                    }
                                }).catch(function (error) {
                                    console.warn('Could not load category payment methods:', error);
                                });
                            },
                            
                            _updatePaymentMethods: function (methods) {
                                const self = this;
                                
                                methods.forEach(function (method) {
                                    const providerEl = self.$el.find(`#payment_provider_${method.id}`);
                                    
                                    if (providerEl.length) {
                                        // Update installment options if provided
                                        if (method.installments && method.installments.length) {
                                            self._updateInstallmentOptions(providerEl, method.installments, method.default_installment);
                                        }
                                        
                                        // Show/hide based on category compatibility
                                        if (method.category_restriction !== 'none') {
                                            providerEl.closest('.o_payment_method_card').show();
                                        }
                                    }
                                });
                            },
                            
                            _updateInstallmentOptions: function (providerEl, installments, defaultVal) {
                                const select = providerEl.find('select[name="installmentCount"]');
                                
                                if (select.length && installments.length) {
                                    const currentVal = select.val();
                                    select.empty();
                                    
                                    installments.forEach(function (opt) {
                                        const label = opt === '1' ? 'Peşin Ödeme' : opt + ' Taksit';
                                        select.append(
                                            $('').val(opt).text(label)
                                        );
                                    });
                                    
                                    // Restore selection or use default
                                    if (installments.includes(currentVal)) {
                                        select.val(currentVal);
                                    } else {
                                        select.val(defaultVal || installments[0]);
                                    }
                                }
                            },
                            
                            _onInstallmentChange: function (ev) {
                                const self = this;
                                const $select = $(ev.currentTarget);
                                const installmentCount = $select.val();
                                const amount = this.$el.find('[name="amount_total"]').val();
                                
                                if (amount && installmentCount) {
                                    // Show loading state
                                    const $totalEl = this.$el.find('.oe_cart_total');
                                    $totalEl.addClass('o_loading');
                                    
                                    // Fetch updated installment calculation
                                    ajax.jsonRpc('/payment/paratika/calculate_installment', 'call', {
                                        amount: parseFloat(amount),
                                        installment_count: parseInt(installmentCount),
                                    }).then(function (result) {
                                        if (result.success) {
                                            // Update display with new installment info
                                            self._updateInstallmentDisplay(result.calculation);
                                        }
                                    }).finally(function () {
                                        $totalEl.removeClass('o_loading');
                                    });
                                }
                            },
                            
                            _updateInstallmentDisplay: function (calc) {
                                // Update total display with installment breakdown
                                const $totalEl = this.$el.find('.oe_cart_total');
                                const breakdown = `



Taksit Başına: ${calc.currency} ${calc.per_installment.toFixed(2)}
                                        ${calc.total_interest > 0 ? `
Toplam Faiz: ${calc.currency} ${calc.total_interest.toFixed(2)}` : ''}

Toplam Tutar: ${calc.currency} ${calc.total_amount.toFixed(2)}
                                    
                                `;
                                $totalEl.find('.installment-breakdown').remove();
                                $totalEl.append(breakdown);
                            },
                            
                            _onBankSelect: function (ev) {
                                const $option = $(ev.currentTarget);
                                const bankCode = $option.data('bank');
                                
                                // Visual feedback
                                $option.closest('.bank-selector').find('.bank-option').removeClass('active border-primary');
                                $option.addClass('active border-primary');
                                
                                // Update hidden input
                                this.$el.find('#paratika_bank').val(bankCode);
                            }
                        });
                        
                        return publicWidget.registry.ParatikaCategoryPayment;
                    });
